use log::info;use std::io::Write;use std::path::PathBuf;use tauri::AppHandle;use tauri_plugin_store::StoreExt;pub async fn run_external_plugin(    app: AppHandle,    plugin_id: String,    plugin_name: String,    cmd: String,    payload: serde_json::Value,) -> Result<String, String> {    info!(        "invoke_external_plugin: {:?}, {:?}, {:?}, {:?}",        plugin_id, plugin_name, cmd, payload    );    match app.store("settings.json") {        Ok(store) => {            let plugin_path = store.get("pluginPath").expect("插件路径获取失败");            let plugin_path = plugin_path.as_str().expect("插件路径转字符串格式失败");            let plugin_path = build_plugin_path(plugin_path, &plugin_id, &plugin_name);            let input = serde_json::json!({ "cmd": cmd, "payload": payload }).to_string();            info!("plugin_path: {:?}", plugin_path);            let app_data_dir = dirs::data_dir()                .map(|d| d.join(app.config().identifier.clone()))                .unwrap_or_else(|| PathBuf::from("."));            let mut child = std::process::Command::new(plugin_path)                .stdin(std::process::Stdio::piped())                .stdout(std::process::Stdio::piped())                .stderr(std::process::Stdio::piped())                .env("EASYPASTE_DATA_DIR", app_data_dir.to_string_lossy().to_string())                .spawn()                .map_err(|e| format!("Failed to spawn plugin: {}", e))?;            {                let mut stdin = child.stdin.take().unwrap();                stdin                    .write_all(input.as_bytes())                    .map_err(|e| format!("Failed to write to plugin stdin: {}", e))?;            }            let output = child                .wait_with_output()                .map_err(|e| format!("Plugin process failed: {}", e))?;            if output.status.success() {                let stdout_str = String::from_utf8(output.stdout)                    .map_err(|e| format!("Invalid UTF-8 from plugin: {}", e))?;                Ok(stdout_str.trim().to_string())            } else {                let stderr_str = String::from_utf8_lossy(&output.stderr);                Err(format!(                    "Plugin exited with error (code {}): {}",                    output.status.code().unwrap_or(-1),                    stderr_str                ))            }        }        _ => Err("插件文件夹获取失败".into()),    }}fn build_plugin_path(plugin_path: &str, plugin_id: &str, plugin_name: &str) -> String {    let mut path = PathBuf::new();    path.push(plugin_path);    path.push(plugin_id);    path.push("rust");    path.push(plugin_name);    path.to_string_lossy().to_string()}